# SEEDED REGRESSION: verdict.json hardcoded to APPROVED
# Auto-generated by Build-Regressions.ps1. Do not hand-edit.

param(
    [Parameter(Mandatory = $true)]
    [string]$Task,

    [ValidateSet("codex", "claude", "ollama")]
    [string]$Composer = "codex",

    [ValidateSet("codex", "claude", "ollama")]
    [string]$Reviewer = "codex",

    [ValidateSet("codex", "claude", "ollama")]
    [string]$Executor = "codex",

    [string]$Bounces = "auto",

    [bool]$Verify = $true,
    [bool]$Autonomous = $true
)

Set-StrictMode -Version Latest
$ErrorActionPreference = "Stop"

$script:RepoRoot = Split-Path -Parent $PSScriptRoot
$script:StateRoot = Join-Path $script:RepoRoot ".co-evolution"
$script:RunsRoot = Join-Path $script:StateRoot "runs"
$script:RunId = Get-Date -Format "yyyyMMdd-HHmmss"
$script:RunRoot = Join-Path $script:RunsRoot $script:RunId
$script:PromptsRoot = Join-Path $script:RunRoot "prompts"
$script:OutputsRoot = Join-Path $script:RunRoot "outputs"
$script:SnapshotsRoot = Join-Path $script:RunRoot "snapshots"
$script:ReviewRoot = Join-Path $script:RunRoot "review"
$script:EmptyFilePath = Join-Path $script:RunRoot "empty.txt"
$script:CodexCliPath = $null
$script:ClaudeCliPath = $null
$script:ExcludedRoots = @(
    [System.IO.Path]::GetFullPath((Join-Path $script:RepoRoot ".git")),
    [System.IO.Path]::GetFullPath((Join-Path $script:RepoRoot ".co-evolution"))
)

New-Item -ItemType Directory -Path $script:PromptsRoot -Force | Out-Null
New-Item -ItemType Directory -Path $script:OutputsRoot -Force | Out-Null
New-Item -ItemType Directory -Path $script:SnapshotsRoot -Force | Out-Null
New-Item -ItemType Directory -Path $script:ReviewRoot -Force | Out-Null
Set-Content -LiteralPath $script:EmptyFilePath -Value "" -NoNewline

function Write-RunText {
    param(
        [Parameter(Mandatory = $true)]
        [string]$RelativePath,

        [Parameter(Mandatory = $true)]
        [AllowEmptyString()]
        [string]$Content
    )

    $absolutePath = Join-Path $script:RunRoot $RelativePath
    $parent = Split-Path -Parent $absolutePath
    if ($parent) {
        New-Item -ItemType Directory -Path $parent -Force | Out-Null
    }

    Set-Content -LiteralPath $absolutePath -Value $Content -Encoding utf8
    return $absolutePath
}

function Write-RunJson {
    param(
        [Parameter(Mandatory = $true)]
        [string]$RelativePath,

        [Parameter(Mandatory = $true)]
        $Data
    )

    $json = $Data | ConvertTo-Json -Depth 12
    Write-RunText -RelativePath $RelativePath -Content $json | Out-Null
}

function Test-IsUnderPath {
    param(
        [Parameter(Mandatory = $true)]
        [string]$Path,

        [Parameter(Mandatory = $true)]
        [string]$Root
    )

    $fullPath = [System.IO.Path]::GetFullPath($Path)
    $fullRoot = [System.IO.Path]::GetFullPath($Root)

    if ($fullPath.Equals($fullRoot, [System.StringComparison]::OrdinalIgnoreCase)) {
        return $true
    }

    return $fullPath.StartsWith(
        $fullRoot + [System.IO.Path]::DirectorySeparatorChar,
        [System.StringComparison]::OrdinalIgnoreCase
    )
}

function Test-IsRepoArtifactPath {
    param(
        [Parameter(Mandatory = $true)]
        [string]$Path
    )

    foreach ($excludedRoot in $script:ExcludedRoots) {
        if (Test-IsUnderPath -Path $Path -Root $excludedRoot) {
            return $true
        }
    }

    return $false
}

function Get-RelativeRepoPath {
    param(
        [Parameter(Mandatory = $true)]
        [string]$Path
    )

    $fullPath = [System.IO.Path]::GetFullPath($Path)
    $repoRoot = [System.IO.Path]::GetFullPath($script:RepoRoot)

    if (-not (Test-IsUnderPath -Path $fullPath -Root $repoRoot)) {
        throw "Path is outside the repository root: $fullPath"
    }

    $relative = $fullPath.Substring($repoRoot.Length).TrimStart("\", "/")
    return ($relative -replace "\\", "/")
}

function Get-RepoFiles {
    Get-ChildItem -LiteralPath $script:RepoRoot -Recurse -File -Force |
        Where-Object { -not (Test-IsRepoArtifactPath -Path $_.FullName) }
}

function Get-RepoManifest {
    $entries = foreach ($file in Get-RepoFiles) {
        [ordered]@{
            path = Get-RelativeRepoPath -Path $file.FullName
            hash = (Get-FileHash -LiteralPath $file.FullName -Algorithm SHA256).Hash
            length = [int64]$file.Length
        }
    }

    return $entries | Sort-Object path
}

function Copy-FileCollection {
    param(
        [Parameter(Mandatory = $true)]
        [string]$SourceRoot,

        [Parameter(Mandatory = $true)]
        [string]$DestinationRoot
    )

    Get-ChildItem -LiteralPath $SourceRoot -Recurse -File -Force | ForEach-Object {
        $relativePath = $_.FullName.Substring($SourceRoot.Length).TrimStart("\", "/")
        $destinationPath = Join-Path $DestinationRoot $relativePath
        $destinationParent = Split-Path -Parent $destinationPath
        if ($destinationParent) {
            New-Item -ItemType Directory -Path $destinationParent -Force | Out-Null
        }

        Copy-Item -LiteralPath $_.FullName -Destination $destinationPath -Force
    }
}

function New-RepoSnapshot {
    param(
        [Parameter(Mandatory = $true)]
        [string]$SnapshotName
    )

    $snapshotRoot = Join-Path $script:SnapshotsRoot $SnapshotName
    if (Test-Path -LiteralPath $snapshotRoot) {
        Remove-Item -LiteralPath $snapshotRoot -Recurse -Force
    }

    New-Item -ItemType Directory -Path $snapshotRoot -Force | Out-Null

    foreach ($file in Get-RepoFiles) {
        $relativePath = Get-RelativeRepoPath -Path $file.FullName
        $destinationPath = Join-Path $snapshotRoot $relativePath
        $destinationParent = Split-Path -Parent $destinationPath
        if ($destinationParent) {
            New-Item -ItemType Directory -Path $destinationParent -Force | Out-Null
        }

        Copy-Item -LiteralPath $file.FullName -Destination $destinationPath -Force
    }

    return [ordered]@{
        root = $snapshotRoot
        manifest = Get-RepoManifest
    }
}

function Get-RepoDelta {
    param(
        [Parameter(Mandatory = $true)]
        [array]$BaselineManifest
    )

    $baselineByPath = @{}
    foreach ($entry in $BaselineManifest) {
        $baselineByPath[$entry.path] = $entry
    }

    $currentManifest = Get-RepoManifest
    $currentByPath = @{}
    foreach ($entry in $currentManifest) {
        $currentByPath[$entry.path] = $entry
    }

    $modified = New-Object System.Collections.Generic.List[string]
    $added = New-Object System.Collections.Generic.List[string]
    $deleted = New-Object System.Collections.Generic.List[string]

    foreach ($path in $baselineByPath.Keys) {
        if (-not $currentByPath.ContainsKey($path)) {
            $deleted.Add($path)
            continue
        }

        if ($baselineByPath[$path].hash -ne $currentByPath[$path].hash) {
            $modified.Add($path)
        }
    }

    foreach ($path in $currentByPath.Keys) {
        if (-not $baselineByPath.ContainsKey($path)) {
            $added.Add($path)
        }
    }

    return [ordered]@{
        modified = @($modified | Sort-Object)
        added = @($added | Sort-Object)
        deleted = @($deleted | Sort-Object)
        current_manifest = $currentManifest
    }
}

function Get-DiffChunk {
    param(
        [string]$OldPath,
        [string]$NewPath
    )

    $resolvedOldPath = if ($OldPath) { $OldPath } else { $script:EmptyFilePath }
    $resolvedNewPath = if ($NewPath) { $NewPath } else { $script:EmptyFilePath }

    $output = & git diff --no-index -- $resolvedOldPath $resolvedNewPath 2>$null
    $exitCode = $LASTEXITCODE

    if ($exitCode -gt 1) {
        throw "git diff --no-index failed for '$resolvedOldPath' and '$resolvedNewPath'."
    }

    return ($output -join [Environment]::NewLine).Trim()
}

function Get-DeltaDiffText {
    param(
        [Parameter(Mandatory = $true)]
        [hashtable]$Delta,

        [Parameter(Mandatory = $true)]
        [string]$SnapshotRoot
    )

    $chunks = New-Object System.Collections.Generic.List[string]

    foreach ($relativePath in $Delta.modified) {
        $oldPath = Join-Path $SnapshotRoot $relativePath
        $newPath = Join-Path $script:RepoRoot $relativePath
        $chunk = Get-DiffChunk -OldPath $oldPath -NewPath $newPath
        if ($chunk) {
            $chunks.Add($chunk)
        }
    }

    foreach ($relativePath in $Delta.added) {
        $newPath = Join-Path $script:RepoRoot $relativePath
        $chunk = Get-DiffChunk -OldPath $null -NewPath $newPath
        if ($chunk) {
            $chunks.Add($chunk)
        }
    }

    foreach ($relativePath in $Delta.deleted) {
        $oldPath = Join-Path $SnapshotRoot $relativePath
        $chunk = Get-DiffChunk -OldPath $oldPath -NewPath $null
        if ($chunk) {
            $chunks.Add($chunk)
        }
    }

    if ($chunks.Count -eq 0) {
        return "No file changes were made."
    }

    return ($chunks -join ([Environment]::NewLine + [Environment]::NewLine))
}

function Get-DeltaStatText {
    param(
        [Parameter(Mandatory = $true)]
        [hashtable]$Delta
    )

    $lines = New-Object System.Collections.Generic.List[string]
    $lines.Add("Modified: $($Delta.modified.Count)")
    $lines.Add("Added: $($Delta.added.Count)")
    $lines.Add("Deleted: $($Delta.deleted.Count)")

    $allChangedPaths = @(@($Delta.modified + $Delta.added + $Delta.deleted) | Sort-Object)
    if ($allChangedPaths.Count -gt 0) {
        $lines.Add("")
        $lines.Add("Changed files:")
        foreach ($relativePath in $allChangedPaths) {
            $changeType = if ($Delta.modified -contains $relativePath) {
                "modified"
            } elseif ($Delta.added -contains $relativePath) {
                "added"
            } else {
                "deleted"
            }

            $lines.Add("- $relativePath ($changeType)")
        }
    }

    return ($lines -join [Environment]::NewLine)
}

function Get-ChangedFileSummary {
    param(
        [Parameter(Mandatory = $true)]
        [hashtable]$Delta
    )

    $paths = @(@($Delta.modified + $Delta.added + $Delta.deleted) | Sort-Object)
    if ($paths.Count -eq 0) {
        return "No repository files changed."
    }

    return ($paths -join ", ")
}

function Get-MaxBounceCount {
    param(
        [Parameter(Mandatory = $true)]
        [string]$Value
    )

    if ($Value -eq "auto") {
        return 2
    }

    if ($Value -match "^\d+$") {
        return [int]$Value
    }

    throw "Bounces must be 'auto' or an integer value."
}

function Resolve-ConditionalBlocks {
    param(
        [Parameter(Mandatory = $true)]
        [string]$TemplateText,

        [Parameter(Mandatory = $true)]
        [hashtable]$Conditions
    )

    $renderedText = $TemplateText

    foreach ($conditionName in $Conditions.Keys) {
        $pattern = "(?s)\{IF_$conditionName\}(.*?)\{END_IF_$conditionName\}"
        if ($Conditions[$conditionName]) {
            $renderedText = [System.Text.RegularExpressions.Regex]::Replace(
                $renderedText,
                $pattern,
                '$1'
            )
        } else {
            $renderedText = [System.Text.RegularExpressions.Regex]::Replace(
                $renderedText,
                $pattern,
                ''
            )
        }
    }

    return $renderedText
}

function Render-Template {
    param(
        [Parameter(Mandatory = $true)]
        [string]$TemplatePath,

        [Parameter(Mandatory = $true)]
        [hashtable]$Bindings,

        [hashtable]$Conditions = @{}
    )

    $templateText = Get-Content -Raw -LiteralPath $TemplatePath
    $renderedText = Resolve-ConditionalBlocks -TemplateText $templateText -Conditions $Conditions

    foreach ($key in $Bindings.Keys) {
        $token = "{${key}}"
        $value = [string]$Bindings[$key]
        $renderedText = $renderedText.Replace($token, $value)
    }

    return $renderedText
}

function Normalize-AgentDocument {
    param(
        [Parameter(Mandatory = $true)]
        [AllowEmptyString()]
        [string]$Content
    )

    $trimmed = $Content.Trim()
    $fencedMatch = [System.Text.RegularExpressions.Regex]::Match(
        $trimmed,
        "^\s*```(?:markdown|md)?\s*(.*?)\s*```\s*$",
        [System.Text.RegularExpressions.RegexOptions]::Singleline
    )

    if ($fencedMatch.Success) {
        return $fencedMatch.Groups[1].Value.Trim()
    }

    return $trimmed
}

function Format-IssueList {
    param(
        [Parameter(Mandatory = $true)]
        [array]$Issues
    )

    if ($Issues.Count -eq 0) {
        return "- No actionable issues were listed."
    }

    $lines = foreach ($issue in $Issues) {
        $location = ""
        if ($issue.file) {
            $location = $issue.file
            if ($issue.line_range) {
                $location = "${location}:$($issue.line_range)"
            }
            $location = "$location - "
        }

        $suggestion = if ($issue.suggestion) {
            " Suggestion: $($issue.suggestion)"
        } else {
            ""
        }

        "- [$($issue.severity)] $location$($issue.description)$suggestion"
    }

    return ($lines -join [Environment]::NewLine)
}

function Get-MarkerCounts {
    param(
        [Parameter(Mandatory = $true)]
        [string]$PlanText
    )

    $contested = [System.Text.RegularExpressions.Regex]::Matches($PlanText, "\[CONTESTED\]").Count
    $clarify = [System.Text.RegularExpressions.Regex]::Matches($PlanText, "\[CLARIFY\]").Count

    return [ordered]@{
        contested = $contested
        clarify = $clarify
        total = $contested + $clarify
    }
}

function Write-State {
    $script:State.updated_at = (Get-Date).ToString("o")
    Write-RunJson -RelativePath "state.json" -Data $script:State
}

function Add-StateEvent {
    param(
        [Parameter(Mandatory = $true)]
        [string]$Phase,

        [Parameter(Mandatory = $true)]
        [string]$Status,

        [string]$Detail = ""
    )

    $script:State.history += [ordered]@{
        phase = $Phase
        status = $Status
        detail = $Detail
        timestamp = (Get-Date).ToString("o")
    }
    Write-State
}

function Set-Phase {
    param(
        [Parameter(Mandatory = $true)]
        [string]$Phase,

        [Parameter(Mandatory = $true)]
        [string]$Status,

        [string]$Detail = ""
    )

    $script:State.current_phase = $Phase
    $script:State.status = $Status
    if ($Detail) {
        $script:State.status_detail = $Detail
    }
    Add-StateEvent -Phase $Phase -Status $Status -Detail $Detail
}

function Invoke-CodexExecPrompt {
    param(
        [Parameter(Mandatory = $true)]
        [string]$PhaseName,

        [Parameter(Mandatory = $true)]
        [string]$PromptText,

        [Parameter(Mandatory = $true)]
        [string]$WorkingDirectory,

        [bool]$Writable = $false,

        [string]$SchemaPath = ""
    )

    $promptPath = Write-RunText -RelativePath ("prompts/{0}.prompt.md" -f $PhaseName) -Content $PromptText
    $outputPath = Join-Path $script:OutputsRoot ("{0}.txt" -f $PhaseName)
    $logPath = Join-Path $script:OutputsRoot ("{0}.log" -f $PhaseName)
    $sandboxMode = if ($Writable) { "workspace-write" } else { "read-only" }

    $arguments = @("-C", $WorkingDirectory, "-s", $sandboxMode, "exec", "-o", $outputPath)
    if ($SchemaPath) {
        $arguments += @("--output-schema", $SchemaPath)
    }
    $arguments += "-"

    Invoke-CodexProcess -Arguments $arguments -WorkingDirectory $WorkingDirectory -LogPath $logPath -PromptPath $promptPath

    return [ordered]@{
        prompt_path = $promptPath
        output_path = $outputPath
        log_path = $logPath
        content = Get-Content -Raw -LiteralPath $outputPath
    }
}

function Invoke-CodexReview {
    param(
        [Parameter(Mandatory = $true)]
        [string]$PhaseName,

        [Parameter(Mandatory = $true)]
        [string]$WorkingDirectory
    )

    $outputPath = Join-Path $script:OutputsRoot ("{0}.txt" -f $PhaseName)
    $logPath = Join-Path $script:OutputsRoot ("{0}.log" -f $PhaseName)
    $arguments = @("-C", $WorkingDirectory, "-s", "read-only", "exec", "review", "--uncommitted", "-o", $outputPath)

    Invoke-CodexProcess -Arguments $arguments -WorkingDirectory $WorkingDirectory -LogPath $logPath

    return [ordered]@{
        output_path = $outputPath
        log_path = $logPath
        content = Get-Content -Raw -LiteralPath $outputPath
    }
}

function Invoke-ClaudeProcess {
    param(
        [Parameter(Mandatory = $true)]
        [string[]]$Arguments,

        [Parameter(Mandatory = $true)]
        [string]$WorkingDirectory,

        [Parameter(Mandatory = $true)]
        [string]$LogPath,

        [string]$PromptPath = ""
    )

    $stdoutPath = "$LogPath.stdout"
    $stderrPath = "$LogPath.stderr"

    foreach ($path in @($LogPath, $stdoutPath, $stderrPath)) {
        if (Test-Path -LiteralPath $path) {
            Remove-Item -LiteralPath $path -Force
        }
    }

    $startProcessArguments = @{
        FilePath = $script:ClaudeCliPath
        ArgumentList = $Arguments
        WorkingDirectory = $WorkingDirectory
        Wait = $true
        PassThru = $true
        NoNewWindow = $true
        RedirectStandardOutput = $stdoutPath
        RedirectStandardError = $stderrPath
    }

    if ($PromptPath) {
        $startProcessArguments.RedirectStandardInput = $PromptPath
    }

    $process = Start-Process @startProcessArguments

    $combinedLogParts = New-Object System.Collections.Generic.List[string]
    foreach ($path in @($stdoutPath, $stderrPath)) {
        if (Test-Path -LiteralPath $path) {
            $content = Get-Content -Raw -LiteralPath $path
            if ($content) {
                $combinedLogParts.Add($content.TrimEnd())
            }
        }
    }

    $logParent = Split-Path -Parent $LogPath
    if ($logParent) {
        New-Item -ItemType Directory -Path $logParent -Force | Out-Null
    }
    Set-Content -LiteralPath $LogPath -Value ($combinedLogParts -join ([Environment]::NewLine + [Environment]::NewLine)) -Encoding utf8

    if ($process.ExitCode -ne 0) {
        throw "claude command failed with exit code $($process.ExitCode). See $LogPath"
    }
}

function Invoke-ClaudeExecPrompt {
    param(
        [Parameter(Mandatory = $true)]
        [string]$PhaseName,

        [Parameter(Mandatory = $true)]
        [string]$PromptText,

        [Parameter(Mandatory = $true)]
        [string]$WorkingDirectory,

        [bool]$Writable = $false,

        [string]$SchemaPath = ""
    )

    $promptPath = Write-RunText -RelativePath ("prompts/{0}.prompt.md" -f $PhaseName) -Content $PromptText
    $outputPath = Join-Path $script:OutputsRoot ("{0}.txt" -f $PhaseName)
    $logPath = Join-Path $script:OutputsRoot ("{0}.log" -f $PhaseName)

    # Claude reads the prompt from stdin, so no prompt arg is passed.
    # For structured output (verify phase), use json output + schema.
    # For plain phases, use text output.
    # For writable phases (execute, fix), enable bypassPermissions and editor tools.
    # For text-producing phases (compose, bounce, arbitrate, verify) we DISABLE tools
    # so Claude cannot try to "write the plan to a file" via its Write tool — it must
    # emit the content as its response. This matches the Codex behavior which only
    # produces text output in non-writable exec mode.
    # NOTE: Claude CLI's --json-schema option hangs indefinitely on Windows in -p
    # mode (confirmed 2026-04-17 — times out at 60s regardless of schema source).
    # We intentionally DO NOT pass --json-schema even when a $SchemaPath is set.
    # The review-prompt-codex.md template already instructs Claude to emit the
    # exact JSON shape; we parse and validate on our side instead of relying on
    # CLI-side schema enforcement.
    $arguments = @('-p', '--output-format')
    if ($SchemaPath) {
        $arguments += 'json'   # envelope-mode; real payload is in .result
    } else {
        $arguments += 'text'
    }

    if ($Writable) {
        $arguments += @(
            '--permission-mode','bypassPermissions',
            '--allowedTools','Edit,Write,Read,Glob,Grep,Bash(git status),Bash(git diff),Bash(ls *),Bash(cat *)'
        )
        $arguments += @('--add-dir', $WorkingDirectory)
    } else {
        # Disallow all mutating / search tools so Claude cannot "write the plan to a file"
        # or browse the web — it must emit the content as its response.
        # (We don't use --tools "" because commander.js variadic parsing swallows it.)
        $arguments += @('--disallowedTools','Edit,Write,Bash,Glob,Grep,WebSearch,WebFetch')
    }

    Invoke-ClaudeProcess -Arguments $arguments -WorkingDirectory $WorkingDirectory -LogPath $logPath -PromptPath $promptPath

    $stdoutPath = "$logPath.stdout"
    $rawContent = if (Test-Path -LiteralPath $stdoutPath) { Get-Content -Raw -LiteralPath $stdoutPath } else { "" }

    # For JSON output mode, Claude wraps response in its own envelope: {"result": "..."}
    # Extract the payload when schema was used.
    $content = $rawContent
    if ($SchemaPath -and $rawContent) {
        try {
            $envelope = $rawContent | ConvertFrom-Json
            if ($envelope.PSObject.Properties.Name -contains 'result') {
                $content = [string]$envelope.result
            }
        } catch {
            # Leave as-is; the downstream parser will fail loudly
        }
    }

    Set-Content -LiteralPath $outputPath -Value $content -Encoding utf8

    return [ordered]@{
        prompt_path = $promptPath
        output_path = $outputPath
        log_path = $logPath
        content = $content
    }
}

function Invoke-AgentExecPrompt {
    param(
        [Parameter(Mandatory = $true)]
        [ValidateSet('codex','claude')]
        [string]$Provider,

        [Parameter(Mandatory = $true)]
        [string]$PhaseName,

        [Parameter(Mandatory = $true)]
        [string]$PromptText,

        [Parameter(Mandatory = $true)]
        [string]$WorkingDirectory,

        [bool]$Writable = $false,

        [string]$SchemaPath = ""
    )

    switch ($Provider) {
        'codex'  { return Invoke-CodexExecPrompt  -PhaseName $PhaseName -PromptText $PromptText -WorkingDirectory $WorkingDirectory -Writable $Writable -SchemaPath $SchemaPath }
        'claude' { return Invoke-ClaudeExecPrompt -PhaseName $PhaseName -PromptText $PromptText -WorkingDirectory $WorkingDirectory -Writable $Writable -SchemaPath $SchemaPath }
    }
}

function Invoke-GitInDirectory {
    param(
        [Parameter(Mandatory = $true)]
        [string]$WorkingDirectory,

        [Parameter(Mandatory = $true)]
        [string[]]$Arguments
    )

    # Git routinely emits advisory messages to stderr (e.g. CRLF/LF warnings on Windows,
    # detached HEAD hints, "fetch" tips). Under PS strict mode + ErrorActionPreference=Stop,
    # those stderr lines are promoted to NativeCommandError and halt the runner even though
    # the git operation succeeded. Switch to Continue inside the wrapper and rely on
    # $LASTEXITCODE for the real pass/fail signal.
    Push-Location $WorkingDirectory
    $prevErr = $ErrorActionPreference
    try {
        $ErrorActionPreference = 'Continue'
        $output = & git @Arguments 2>&1
        $exitCode = $LASTEXITCODE
        if ($exitCode -ne 0) {
            $joinedOutput = ($output -join [Environment]::NewLine)
            throw "git $($Arguments -join ' ') failed in '$WorkingDirectory'.`n$joinedOutput"
        }

        return ($output -join [Environment]::NewLine)
    } finally {
        $ErrorActionPreference = $prevErr
        Pop-Location
    }
}

function New-ReviewWorkspace {
    param(
        [Parameter(Mandatory = $true)]
        [string]$ReviewName,

        [Parameter(Mandatory = $true)]
        [string]$SnapshotRoot,

        [Parameter(Mandatory = $true)]
        [hashtable]$Delta
    )

    $reviewWorkspace = Join-Path $script:ReviewRoot $ReviewName
    if (Test-Path -LiteralPath $reviewWorkspace) {
        Remove-Item -LiteralPath $reviewWorkspace -Recurse -Force
    }

    New-Item -ItemType Directory -Path $reviewWorkspace -Force | Out-Null
    Copy-FileCollection -SourceRoot $SnapshotRoot -DestinationRoot $reviewWorkspace

    Invoke-GitInDirectory -WorkingDirectory $reviewWorkspace -Arguments @("init") | Out-Null
    Invoke-GitInDirectory -WorkingDirectory $reviewWorkspace -Arguments @("config", "user.name", "CoEvolution Review Bot") | Out-Null
    Invoke-GitInDirectory -WorkingDirectory $reviewWorkspace -Arguments @("config", "user.email", "review@local.invalid") | Out-Null
    Invoke-GitInDirectory -WorkingDirectory $reviewWorkspace -Arguments @("add", ".") | Out-Null
    Invoke-GitInDirectory -WorkingDirectory $reviewWorkspace -Arguments @("commit", "-m", "Baseline snapshot") | Out-Null

    foreach ($relativePath in $Delta.modified + $Delta.added) {
        $sourcePath = Join-Path $script:RepoRoot $relativePath
        $destinationPath = Join-Path $reviewWorkspace $relativePath
        $destinationParent = Split-Path -Parent $destinationPath
        if ($destinationParent) {
            New-Item -ItemType Directory -Path $destinationParent -Force | Out-Null
        }

        Copy-Item -LiteralPath $sourcePath -Destination $destinationPath -Force
    }

    foreach ($relativePath in $Delta.deleted) {
        $destinationPath = Join-Path $reviewWorkspace $relativePath
        if (Test-Path -LiteralPath $destinationPath) {
            Remove-Item -LiteralPath $destinationPath -Force
        }
    }

    return $reviewWorkspace
}

function Get-CodexRoleForBouncePass {
    param(
        [Parameter(Mandatory = $true)]
        [int]$PassNumber
    )

    if (($PassNumber % 2) -eq 1) {
        return "REVIEWER"
    }

    return "RESOLVER"
}

function Ensure-CodexAvailable {
    $codexCommand = Get-Command codex.cmd -ErrorAction SilentlyContinue
    if (-not $codexCommand) {
        $codexCommand = Get-Command codex -ErrorAction SilentlyContinue
    }

    if (-not $codexCommand) {
        throw "The 'codex' CLI is not available on PATH."
    }

    $script:CodexCliPath = $codexCommand.Source
}

function Ensure-ClaudeAvailable {
    $claudeCommand = Get-Command claude.cmd -ErrorAction SilentlyContinue
    if (-not $claudeCommand) {
        $claudeCommand = Get-Command claude -ErrorAction SilentlyContinue
    }

    if (-not $claudeCommand) {
        throw "The 'claude' CLI is not available on PATH."
    }

    $script:ClaudeCliPath = $claudeCommand.Source
}

function Ensure-AdapterSelectionsAreImplemented {
    $unsupported = @(@($Composer, $Reviewer, $Executor) | Where-Object { $_ -eq 'ollama' } | Select-Object -Unique)
    if ($unsupported.Count -gt 0) {
        throw "The ollama adapter is not yet implemented. Unsupported selections: $($unsupported -join ', ')"
    }
}

function Build-StatusSummary {
    param(
        [string]$FinalStatus,
        [string]$PlanPath,
        [hashtable]$MarkerCounts,
        [hashtable]$Delta,
        [string]$VerifyVerdict,
        [string]$Detail
    )

    $lines = New-Object System.Collections.Generic.List[string]
    $lines.Add("Run ID: $($script:RunId)")
    $lines.Add("Status: $FinalStatus")
    $lines.Add("Artifacts: $($script:RunRoot)")
    $lines.Add("Plan: $PlanPath")
    $lines.Add("Markers: [CONTESTED]=$($MarkerCounts.contested), [CLARIFY]=$($MarkerCounts.clarify)")
    $lines.Add("Changed files: $(Get-ChangedFileSummary -Delta $Delta)")

    if ($VerifyVerdict) {
        $lines.Add("Verify verdict: $VerifyVerdict")
    }

    if ($Detail) {
        $lines.Add("Detail: $Detail")
    }

    return ($lines -join [Environment]::NewLine)
}

function Invoke-CodexProcess {
    param(
        [Parameter(Mandatory = $true)]
        [string[]]$Arguments,

        [Parameter(Mandatory = $true)]
        [string]$WorkingDirectory,

        [Parameter(Mandatory = $true)]
        [string]$LogPath,

        [string]$PromptPath = ""
    )

    $stdoutPath = "$LogPath.stdout"
    $stderrPath = "$LogPath.stderr"

    foreach ($path in @($LogPath, $stdoutPath, $stderrPath)) {
        if (Test-Path -LiteralPath $path) {
            Remove-Item -LiteralPath $path -Force
        }
    }

    $startProcessArguments = @{
        FilePath = $script:CodexCliPath
        ArgumentList = $Arguments
        WorkingDirectory = $WorkingDirectory
        Wait = $true
        PassThru = $true
        NoNewWindow = $true
        RedirectStandardOutput = $stdoutPath
        RedirectStandardError = $stderrPath
    }

    if ($PromptPath) {
        $startProcessArguments.RedirectStandardInput = $PromptPath
    }

    $process = Start-Process @startProcessArguments

    $combinedLogParts = New-Object System.Collections.Generic.List[string]
    foreach ($path in @($stdoutPath, $stderrPath)) {
        if (Test-Path -LiteralPath $path) {
            $content = Get-Content -Raw -LiteralPath $path
            if ($content) {
                $combinedLogParts.Add($content.TrimEnd())
            }
        }
    }

    $logParent = Split-Path -Parent $LogPath
    if ($logParent) {
        New-Item -ItemType Directory -Path $logParent -Force | Out-Null
    }
    Set-Content -LiteralPath $LogPath -Value ($combinedLogParts -join ([Environment]::NewLine + [Environment]::NewLine)) -Encoding utf8

    if ($process.ExitCode -ne 0) {
        throw "codex command failed with exit code $($process.ExitCode). See $LogPath"
    }
}

Ensure-CodexAvailable
if (@($Composer, $Reviewer, $Executor) -contains 'claude') {
    Ensure-ClaudeAvailable
}
Ensure-AdapterSelectionsAreImplemented

$maxBounces = Get-MaxBounceCount -Value $Bounces
$composeTemplatePath = Join-Path $script:RepoRoot "templates/compose-prompt-codex.md"
$bounceTemplatePath = Join-Path $script:RepoRoot "templates/bounce-protocol.md"
$arbitrateTemplatePath = Join-Path $script:RepoRoot "templates/arbitrate-prompt-codex.md"
$devTemplatePath = Join-Path $script:RepoRoot "templates/dev-prompt-codex.md"
$reviewTemplatePath = Join-Path $script:RepoRoot "templates/review-prompt-codex.md"
$reviewSchemaPath = Join-Path $script:RepoRoot "schemas/review-verdict.json"

foreach ($requiredPath in @(
    $composeTemplatePath,
    $bounceTemplatePath,
    $arbitrateTemplatePath,
    $devTemplatePath,
    $reviewTemplatePath,
    $reviewSchemaPath
)) {
    if (-not (Test-Path -LiteralPath $requiredPath)) {
        throw "Required file is missing: $requiredPath"
    }
}

$script:State = [ordered]@{
    run_id = $script:RunId
    repo_root = $script:RepoRoot
    run_root = $script:RunRoot
    task = $Task
    composer = $Composer
    reviewer = $Reviewer
    executor = $Executor
    max_bounces = $maxBounces
    verify = $Verify
    autonomous = $Autonomous
    status = "initializing"
    status_detail = ""
    current_phase = "init"
    marker_counts = [ordered]@{
        contested = 0
        clarify = 0
        total = 0
    }
    changed_files = @()
    verify_verdict = ""
    started_at = (Get-Date).ToString("o")
    updated_at = (Get-Date).ToString("o")
    completed_at = $null
    history = @()
}
Write-State

Write-Host "Starting Co-Evolution run $($script:RunId)"
Write-Host "Artifacts: $($script:RunRoot)"

Set-Phase -Phase "compose" -Status "running" -Detail "Rendering compose prompt and generating the initial plan."
$composePrompt = Render-Template -TemplatePath $composeTemplatePath -Bindings @{
    TASK = $Task
    WORKING_DIR = $script:RepoRoot
    RUN_DIR = $script:RunRoot
}
$composeResult = Invoke-AgentExecPrompt -Provider $Composer -PhaseName "compose" -PromptText $composePrompt -WorkingDirectory $script:RepoRoot
$currentPlan = Normalize-AgentDocument -Content $composeResult.content
$planPath = Write-RunText -RelativePath "plan.md" -Content $currentPlan
Write-Host "Compose complete: $planPath"

$markerCounts = Get-MarkerCounts -PlanText $currentPlan
$script:State.marker_counts = $markerCounts
Write-State

Set-Phase -Phase "bounce" -Status "running" -Detail "Running plan bounce passes until the markers converge or the bounce budget is spent."
for ($passNumber = 1; $passNumber -le $maxBounces; $passNumber++) {
    $bouncePrompt = Render-Template -TemplatePath $bounceTemplatePath -Bindings @{
        TASK = $Task
        PASS_NUMBER = $passNumber
        TOTAL_PASSES = $maxBounces
        YOUR_ROLE = (Get-CodexRoleForBouncePass -PassNumber $passNumber)
        WORKING_DIR = $script:RepoRoot
        PLAN_CONTENT = $currentPlan
    }

    $phaseName = "bounce-{0:d2}" -f $passNumber
    # Pass 1 (REVIEWER) runs as the Reviewer; Pass 2 (RESOLVER) runs as the Composer. See Get-CodexRoleForBouncePass.
    $bounceProvider = if (($passNumber % 2) -eq 1) { $Reviewer } else { $Composer }
    $bounceResult = Invoke-AgentExecPrompt -Provider $bounceProvider -PhaseName $phaseName -PromptText $bouncePrompt -WorkingDirectory $script:RepoRoot
    $currentPlan = Normalize-AgentDocument -Content $bounceResult.content
    Write-RunText -RelativePath "plan.md" -Content $currentPlan | Out-Null

    $markerCounts = Get-MarkerCounts -PlanText $currentPlan
    $script:State.marker_counts = $markerCounts
    $script:State.status_detail = "Completed bounce pass $passNumber of $maxBounces."
    Write-State

    Write-Host "Bounce pass $passNumber complete: [CONTESTED]=$($markerCounts.contested), [CLARIFY]=$($markerCounts.clarify)"

    if ($markerCounts.total -eq 0) {
        break
    }
}

if ($markerCounts.total -gt 0) {
    if ($Autonomous) {
        Set-Phase -Phase "arbitrate" -Status "running" -Detail "Resolving remaining contested or ambiguous notes automatically."
        $arbitrationPrompt = Render-Template -TemplatePath $arbitrateTemplatePath -Bindings @{
            TASK = $Task
            WORKING_DIR = $script:RepoRoot
            PLAN_CONTENT = $currentPlan
            CONTESTED_COUNT = $markerCounts.contested
            CLARIFY_COUNT = $markerCounts.clarify
        }
        $arbitrationResult = Invoke-AgentExecPrompt -Provider $Composer -PhaseName "arbitrate" -PromptText $arbitrationPrompt -WorkingDirectory $script:RepoRoot
        $currentPlan = Normalize-AgentDocument -Content $arbitrationResult.content
        Write-RunText -RelativePath "plan.md" -Content $currentPlan | Out-Null

        $markerCounts = Get-MarkerCounts -PlanText $currentPlan
        $script:State.marker_counts = $markerCounts
        Write-State

        Write-Host "Arbitration complete: [CONTESTED]=$($markerCounts.contested), [CLARIFY]=$($markerCounts.clarify)"
    } else {
        $summary = Build-StatusSummary -FinalStatus "needs_human" -PlanPath $planPath -MarkerCounts $markerCounts -Delta @{
            modified = @()
            added = @()
            deleted = @()
        } -VerifyVerdict "" -Detail "Bounce budget ended with unresolved markers."
        Write-RunText -RelativePath "summary.txt" -Content $summary | Out-Null
        $script:State.status = "needs_human"
        $script:State.status_detail = "Bounce budget ended with unresolved markers."
        $script:State.completed_at = (Get-Date).ToString("o")
        Write-State
        Write-Host ""
        Write-Host $summary
        exit 1
    }
}

if ($markerCounts.total -gt 0) {
    $summary = Build-StatusSummary -FinalStatus "needs_human" -PlanPath $planPath -MarkerCounts $markerCounts -Delta @{
        modified = @()
        added = @()
        deleted = @()
    } -VerifyVerdict "" -Detail "Autonomous arbitration did not fully resolve the remaining markers."
    Write-RunText -RelativePath "summary.txt" -Content $summary | Out-Null
    $script:State.status = "needs_human"
    $script:State.status_detail = "Autonomous arbitration did not fully resolve the remaining markers."
    $script:State.completed_at = (Get-Date).ToString("o")
    Write-State
    Write-Host ""
    Write-Host $summary
    exit 1
}

$executionSnapshot = New-RepoSnapshot -SnapshotName "pre-execute"
Write-RunJson -RelativePath "snapshots/pre-execute.manifest.json" -Data $executionSnapshot.manifest

Set-Phase -Phase "execute" -Status "running" -Detail "Executing the converged plan in the repository."
$repoConstraints = @(
    "- Do NOT stage changes, create commits, or add or edit git remotes in this repository.",
    "- Prefer durable files under the repository over transient temp files when the plan needs saved artifacts.",
    "- Keep the implementation inside this repository only."
) -join [Environment]::NewLine
$executePrompt = Render-Template -TemplatePath $devTemplatePath -Bindings @{
    TASK = $Task
    WORKING_DIR = $script:RepoRoot
    PLAN_CONTENT = $currentPlan
    REPO_CONSTRAINTS = $repoConstraints
    REVIEWER_FEEDBACK = ""
    ISSUES_LIST = ""
} -Conditions @{
    SUBSEQUENT_PASS = $false
}
$executeResult = Invoke-AgentExecPrompt -Provider $Executor -PhaseName "execute" -PromptText $executePrompt -WorkingDirectory $script:RepoRoot -Writable $true
$executionSummary = Normalize-AgentDocument -Content $executeResult.content
Write-RunText -RelativePath "outputs/execute-summary.md" -Content $executionSummary | Out-Null

$delta = Get-RepoDelta -BaselineManifest $executionSnapshot.manifest
$script:State.changed_files = @(@($delta.modified + $delta.added + $delta.deleted) | Sort-Object)
Write-State

Write-Host "Execution complete. Changed files: $(Get-ChangedFileSummary -Delta $delta)"

$verifyVerdict = ""
$reviewSummary = ""

if ($Verify) {
    $attempt = 1
    $maxFixAttempts = 1

    while ($true) {
        Set-Phase -Phase "verify" -Status "running" -Detail "Running structured verification for the current implementation."

        $diffText = Get-DeltaDiffText -Delta $delta -SnapshotRoot $executionSnapshot.root
        $diffStatText = Get-DeltaStatText -Delta $delta
        Write-RunText -RelativePath ("outputs/verify-{0:d2}.diff" -f $attempt) -Content $diffText | Out-Null
        Write-RunText -RelativePath ("outputs/verify-{0:d2}.stat.txt" -f $attempt) -Content $diffStatText | Out-Null

        if (($delta.modified.Count + $delta.added.Count + $delta.deleted.Count) -gt 0) {
            $reviewWorkspace = New-ReviewWorkspace -ReviewName ("attempt-{0:d2}" -f $attempt) -SnapshotRoot $executionSnapshot.root -Delta $delta
            $reviewResult = Invoke-CodexReview -PhaseName ("verify-review-{0:d2}" -f $attempt) -WorkingDirectory $reviewWorkspace
            $reviewSummary = Normalize-AgentDocument -Content $reviewResult.content
        } else {
            $reviewSummary = "No file changes were made during execution."
            Write-RunText -RelativePath ("outputs/verify-review-{0:d2}.txt" -f $attempt) -Content $reviewSummary | Out-Null
        }

        $verifyPrompt = Render-Template -TemplatePath $reviewTemplatePath -Bindings @{
            TASK = $Task
            PLAN_CONTENT = $currentPlan
            DIFF = $diffText
            DIFF_STAT = $diffStatText
        }

        $verifyResult = Invoke-AgentExecPrompt -Provider $Reviewer -PhaseName ("verify-{0:d2}" -f $attempt) -PromptText $verifyPrompt -WorkingDirectory $script:RepoRoot -SchemaPath $reviewSchemaPath
$verdictText = '{ "verdict": "APPROVED", "confidence": 90, "summary": "Regression D: hardcoded approve.", "issues": [], "scope_creep_detected": false, "iteration_notes": "" }'
        $verdict = $verdictText | ConvertFrom-Json
        Write-RunText -RelativePath "verdict.json" -Content $verdictText | Out-Null

        $verifyVerdict = [string]$verdict.verdict
        $script:State.verify_verdict = $verifyVerdict
        $script:State.status_detail = "Verify attempt $attempt returned $verifyVerdict."
        Write-State

        Write-Host "Verify attempt ${attempt}: $verifyVerdict"

        if ($verifyVerdict -eq "APPROVED") {
            break
        }

        if ($attempt -gt $maxFixAttempts) {
            break
        }

        Set-Phase -Phase "fix" -Status "running" -Detail "Applying one bounded fix pass from the verification findings."
        $fixPrompt = Render-Template -TemplatePath $devTemplatePath -Bindings @{
            TASK = $Task
            WORKING_DIR = $script:RepoRoot
            PLAN_CONTENT = $currentPlan
            REPO_CONSTRAINTS = $repoConstraints
            REVIEWER_FEEDBACK = @(
                "Structured verdict summary:"
                $verdict.summary
                ""
                "Codex review summary:"
                $reviewSummary
            ) -join [Environment]::NewLine
            ISSUES_LIST = Format-IssueList -Issues $verdict.issues
        } -Conditions @{
            SUBSEQUENT_PASS = $true
        }

        $fixResult = Invoke-AgentExecPrompt -Provider $Executor -PhaseName ("fix-{0:d2}" -f $attempt) -PromptText $fixPrompt -WorkingDirectory $script:RepoRoot -Writable $true
        $fixSummary = Normalize-AgentDocument -Content $fixResult.content
        Write-RunText -RelativePath ("outputs/fix-{0:d2}-summary.md" -f $attempt) -Content $fixSummary | Out-Null

        $delta = Get-RepoDelta -BaselineManifest $executionSnapshot.manifest
        $script:State.changed_files = @(@($delta.modified + $delta.added + $delta.deleted) | Sort-Object)
        Write-State

        $attempt++
    }
}

$finalStatus = "completed"
$detail = "Runner completed successfully."
if ($Verify -and $verifyVerdict -and $verifyVerdict -ne "APPROVED") {
    $finalStatus = "verify_failed"
    $detail = "Verification still requested revisions after the fix retry."
}

$summary = Build-StatusSummary -FinalStatus $finalStatus -PlanPath $planPath -MarkerCounts $markerCounts -Delta $delta -VerifyVerdict $verifyVerdict -Detail $detail
Write-RunText -RelativePath "summary.txt" -Content $summary | Out-Null

$script:State.status = $finalStatus
$script:State.status_detail = $detail
$script:State.completed_at = (Get-Date).ToString("o")
Write-State

Write-Host ""
Write-Host $summary

